#include <string>

std::string solve(long long n) {
    // Function to convert a number to a given base (hex or base36)
    std::string convert_to_base(long long num, int base) {
        std::string digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
        std::string result = "";
        if (num == 0) return "0";
        while (num > 0) {
            long long remainder = num % base;
            result = digits[remainder] + result;
            num = num / base;
        }
        return result;
    }

    // Calculate n squared and n cubed
    long long n_squared = n * n;
    long long n_cubed = n * n * n;

    // Convert to hexadecimal and base36
    std::string hex_result = convert_to_base(n_squared, 16);
    std::string base36_result = convert_to_base(n_cubed, 36);

    // Concatenate the results
    return hex_result + base36_result;
}
